# Glossary terms. Each: name, definition (2 sentences), related service slugs. No em dashes.

GLOSSARY = {
"account-abstraction": ("Account Abstraction", "A model where blockchain accounts are smart contracts instead of raw key pairs, enabling features like sponsored gas, session keys, and recovery without seed phrases. Standardized on EVM chains through ERC-4337.", ["wallet-account-abstraction"]),
"erc-4337": ("ERC-4337", "The Ethereum standard that enables smart contract accounts without protocol changes, using a separate mempool of UserOperations processed by bundlers. It is the foundation of most modern wallet UX, from gasless transactions to passkey sign-in.", ["wallet-account-abstraction","smart-contract-development"]),
"amm": ("AMM (Automated Market Maker)", "A decentralized exchange mechanism where liquidity pools and a pricing formula replace order books, letting anyone trade against pooled assets. Variants range from constant-product designs to concentrated liquidity.", ["defi-development"]),
"tvl": ("TVL (Total Value Locked)", "The total value of assets deposited in a protocol's contracts, used as the standard measure of DeFi protocol scale. Rising TVL raises the stakes of every security decision made before launch.", ["defi-development","smart-contract-audit-readiness"]),
"rwa-tokenization": ("RWA Tokenization", "Representing real world assets such as funds, credit, or property as on-chain tokens with legally enforced transfer rules. The engineering is mostly in the rails around the token: identity, restrictions, registries, and redemption.", ["tokenization-rwa"]),
"zk-rollup": ("ZK Rollup", "A layer 2 that executes transactions off-chain and posts validity proofs to the base chain, inheriting its security with far lower costs. Proof generation adds complexity but removes the withdrawal delays of optimistic designs.", ["cross-chain-interoperability","smart-contract-development"]),
"optimistic-rollup": ("Optimistic Rollup", "A layer 2 that posts transactions to the base chain and assumes validity unless challenged during a dispute window. Powers major L2s and trades a withdrawal delay for simpler proving.", ["cross-chain-interoperability"]),
"mev": ("MEV (Maximal Extractable Value)", "Value extracted by reordering, inserting, or censoring transactions within a block, affecting protocols through sandwiching and liquidation races. Serious protocol design treats MEV exposure as an explicit parameter.", ["defi-development","protocol-token-design"]),
"oracle": ("Oracle", "Infrastructure that brings off-chain data such as prices on-chain for contracts to consume. Oracle assumptions are among the most attacked surfaces in DeFi, which is why manipulation cost and fallback design are documented explicitly.", ["defi-development","smart-contract-audit-readiness"]),
"subgraph": ("Subgraph", "An indexing definition on The Graph that transforms raw chain events into queryable GraphQL entities. The standard answer for event indexing; custom indexers take over when joins, aggregation, or latency demand it.", ["blockchain-indexing-data"]),
"chain-reorg": ("Chain Reorganization", "When a blockchain replaces recent blocks with a competing branch, invalidating transactions applications may have already processed. Indexing systems handle it with confirmation depth and rollback-capable storage.", ["blockchain-indexing-data"]),
"multisig": ("Multisig", "A wallet requiring multiple signatures to execute, standard for treasuries and protocol administration. Combined with timelocks, it is the baseline of credible on-chain operations.", ["smart-contract-development","tokenization-rwa"]),
"timelock": ("Timelock", "A contract that delays administrative actions by a fixed period after they are queued, giving users time to react to changes. A standard trust signal for upgradeable protocols.", ["smart-contract-development"]),
"gas-sponsorship": ("Gas Sponsorship", "Paying transaction fees on behalf of users through paymasters, removing the largest onboarding objection in consumer crypto. On L2s the cost is cents and the conversion gain is measurable.", ["wallet-account-abstraction"]),
"invariant-testing": ("Invariant Testing", "Property-based testing that asserts conditions which must always hold, such as conservation of funds, across randomized sequences of operations. Catches the state-dependent bugs unit tests structurally miss.", ["smart-contract-audit-readiness"]),
"fuzzing": ("Fuzzing", "Automatically generating large volumes of randomized inputs to discover edge cases and crashes humans would not think to write. In smart contracts it pairs with invariants to search state space adversarially.", ["smart-contract-audit-readiness","qa-test-automation"]),
"session-keys": ("Session Keys", "Scoped, temporary signing keys that let a user approve a category of actions once instead of confirming every transaction. Core to making on-chain games and consumer apps feel like normal software.", ["wallet-account-abstraction"]),
"cmdb": ("CMDB (Configuration Management Database)", "The system of record for IT assets and their relationships, underpinning impact analysis, change risk, and incident triage. It stays accurate only when discovery and reconciliation are engineered, not hoped for.", ["servicenow-itom-cmdb"]),
"itsm": ("ITSM (IT Service Management)", "The discipline of running IT as defined services: incidents, problems, changes, requests, and knowledge. On ServiceNow it succeeds on process design and adoption, not module activation.", ["servicenow-itsm-implementation"]),
"itom": ("ITOM (IT Operations Management)", "The operational layer above the CMDB: discovery, service mapping, and event management that keep infrastructure visible and alert noise actionable. It is what makes a CMDB self-maintaining.", ["servicenow-itom-cmdb"]),
"hrsd": ("HRSD (HR Service Delivery)", "ServiceNow's HR case, knowledge, and lifecycle-event platform, giving employees one front door for HR while keeping sensitive cases confidential. Succeeds when the portal journey is designed like a product.", ["servicenow-hrsd-csm"]),
"mid-server": ("MID Server", "A ServiceNow agent installed inside your network that lets the platform reach systems behind the firewall for discovery and integrations. Its architecture and credential strategy decide discovery coverage.", ["servicenow-itom-cmdb","servicenow-integrations"]),
"flow-designer": ("Flow Designer", "ServiceNow's low-code automation builder for approvals, tasks, and integrations without scripting. Used with discipline it replaces manual handoffs; used casually it becomes invisible technical debt.", ["servicenow-custom-app-development"]),
"now-assist": ("Now Assist", "ServiceNow's generative AI layer: case summarization, resolution notes, and agent assistance across workflows. It earns its license when pointed at high-volume queues and measured against baselines.", ["servicenow-virtual-agent-ai"]),
"service-catalog": ("Service Catalog", "The storefront of requestable IT and business services, backed by fulfillment automation. Catalog design quality shows up directly in ticket deflection and completion rates.", ["servicenow-itsm-implementation","servicenow-service-portal"]),
"atf": ("ATF (Automated Test Framework)", "ServiceNow's native test automation, used to protect configurations and custom apps through upgrades. Instances with ATF coverage upgrade on schedule; instances without it upgrade on courage.", ["servicenow-custom-app-development","servicenow-managed-services"]),
"rag": ("RAG (Retrieval-Augmented Generation)", "An AI architecture where a model retrieves relevant documents before answering, grounding output in your actual data instead of training memory. Quality lives in chunking, retrieval tuning, and evaluation sets.", ["ai-agentic-automation"]),
"agentic-workflow": ("Agentic Workflow", "An automation where an AI model plans and executes multi-step tasks using tools, with permissions and human approval gates on consequential actions. The production version is mostly error handling and logging.", ["ai-agentic-automation"]),
"llm-evaluation": ("LLM Evaluation", "Testing AI outputs against golden datasets and scoring criteria so model or prompt changes cannot silently degrade quality. The difference between an AI demo and an AI system you can change safely.", ["ai-agentic-automation"]),
"human-in-the-loop": ("Human-in-the-Loop", "An automation pattern where defined steps pause for human review before execution, typically for consequential or ambiguous actions. It is how AI workflows earn trust in real operations.", ["ai-agentic-automation"]),
"strangler-pattern": ("Strangler Pattern", "A modernization strategy where new capabilities are built beside a legacy system and traffic shifts gradually until the old system can be retired. It replaces big-bang rewrites with reversible slices.", ["legacy-modernization"]),
"core-web-vitals": ("Core Web Vitals", "Google's user-experience metrics covering loading, interactivity, and visual stability, which affect both rankings and conversion. Kept honest by budgets enforced in CI rather than audits after the fact.", ["technical-seo-growth","performance-reliability-engineering"]),
"programmatic-seo": ("Programmatic SEO", "Generating many high-quality pages from structured data to capture long-tail search demand, such as services by technology or comparisons. Wins on data quality and internal linking; loses as thin content when either is skipped.", ["technical-seo-growth"]),
"slo": ("SLO (Service Level Objective)", "A target for service reliability, such as 99.9 percent of requests under 300ms, that turns uptime from a feeling into a budget. Burn-rate alerts on SLOs replace pager noise with signal.", ["performance-reliability-engineering"]),
"canary-deployment": ("Canary Deployment", "Releasing a change to a small slice of traffic first, watching real metrics, then rolling forward or back. It converts deploy risk from an event into a dial.", ["devops-platform-engineering"]),
"gitops": ("GitOps", "Operating infrastructure and deployments through pull requests, with a controller reconciling the cluster to what the repository declares. Every change is reviewed, logged, and revertible by design.", ["devops-platform-engineering","cloud-infrastructure"]),
"headless-commerce": ("Headless Commerce", "Separating the storefront frontend from the commerce backend, trading platform defaults for full experience control. Powerful with a real business case; an expensive slowdown without one.", ["shopify-commerce-engineering"]),
}
